// Formater la réponse de débannissement
const response = $input.item.json.result || $input.item.json;
const data = response.data || response;

if (response.status !== 'success') {
  return {
    json: {
      success: false,
      message: `❌ Erreur lors du débannissement: ${response.msg || 'Erreur inconnue'}`,
      error: response.msg
    }
  };
}

let formattedText = `✅ Débannissement effectué avec succès.\n`;

if (data && typeof data === 'object') {
  const instances = Object.keys(data);
  formattedText += `\n**Instances mises à jour:** ${instances.join(', ')}\n`;

  instances.forEach(instance => {
    if (data[instance].status === 'success') {
      formattedText += `\n• ${instance}: ✅ OK`;
    } else {
      formattedText += `\n• ${instance}: ❌ ${data[instance].msg || 'Erreur'}`;
    }
  });
}

return {
  json: {
    success: true,
    message: formattedText,
    data: data
  }
};
